INSERT INTO `medicamentos` (`nombre`, `descripcion`, `presentacion`, `dosis`, `laboratorio`, `categoria`, `efectos_secundarios`, `contraindicaciones`) VALUES
('Ibuprofeno', 'Antiinflamatorio no esteroideo (AINE) utilizado para aliviar el dolor, reducir la fiebre y disminuir la inflamacion. Actua inhibiendo las enzimas COX-1 y COX-2.', 'Tabletas 400 mg y 600 mg', 'Adultos: 400-800 mg cada 6-8 horas. Maximo 3200 mg/dia. Tomar con alimentos.', 'Bayer / Pfizer', 'Analgésico/AINE', 'Molestias gastrointestinales, nauseas, ulceras pepticas con uso prolongado, retencion de liquidos, riesgo cardiovascular.', 'Ulcera peptica activa, insuficiencia renal grave, ultimo trimestre del embarazo, hipersensibilidad a AINEs.'),
('Paracetamol', 'Analgesico y antipiretico de uso comun. Actua a nivel central inhibiendo la sintesis de prostaglandinas. No tiene efecto antiinflamatorio significativo.', 'Tabletas 500 mg y 1000 mg; Jarabe 120 mg/5 mL; Supositorios', 'Adultos: 500-1000 mg cada 4-6 horas. Maximo 4 g/dia. Ninos: 10-15 mg/kg/dosis.', 'Bristol-Myers / Tylenol', 'Analgésico/Antipirético', 'Generalmente bien tolerado. En sobredosis: hepatotoxicidad grave. Raramente: reacciones alergicas cutaneas.', 'Hepatopatia grave, alcoholismo cronico, hipersensibilidad al paracetamol.'),
('Amoxicilina', 'Antibiotico betalactamico de amplio espectro. Inhibe la sintesis de la pared celular bacteriana. Eficaz en infecciones respiratorias, urinarias y de piel.', 'Capsulas 500 mg; Suspension oral 250 mg/5 mL', 'Adultos: 500 mg cada 8 horas o 875 mg cada 12 horas. Curso de 7-10 dias segun infeccion.', 'GlaxoSmithKline / Amoxil', 'Antibiótico', 'Diarrea, nauseas, erupcion cutanea, superinfeccion por candida, colitis pseudomembranosa (rara).', 'Alergia a penicilinas o cefalosporinas, mononucleosis infecciosa.'),
('Metformina', 'Biguanida hipoglucemiante de primera linea para diabetes tipo 2. Reduce la glucosa hepatica y mejora la sensibilidad a la insulina sin causar hipoglucemia.', 'Tabletas 500 mg, 850 mg, 1000 mg (liberacion inmediata y prolongada)', 'Inicial: 500 mg con desayuno y cena. Maximo 2550-3000 mg/dia.', 'Merck / Glucophage', 'Antidiabético', 'Nauseas, diarrea, vomitos, sabor metalico. Rara: acidosis lactica (en insuficiencia renal).', 'Insuficiencia renal (TFG < 30 mL/min), insuficiencia hepatica, alcoholismo, insuficiencia cardiaca descompensada.'),
('Enalapril', 'Inhibidor de la enzima convertidora de angiotensina (IECA). Reduce la presion arterial y protege la funcion renal en diabeticos e hipertensos.', 'Tabletas 5 mg, 10 mg, 20 mg', 'Inicial: 5 mg/dia. Mantenimiento: 10-40 mg/dia en 1 o 2 dosis.', 'Merck / Vasotec', 'Antihipertensivo/IECA', 'Tos seca persistente (muy comun), hipotension de primera dosis, hiperpotasemia, angioedema (raro pero grave).', 'Embarazo (teratogeno), antecedente de angioedema por IECA, estenosis arterial renal bilateral.'),
('Atorvastatina', 'Estatina inhibidora de la HMG-CoA reductasa. Reduce el colesterol LDL y trigliceridos; eleva el HDL. Previene eventos cardiovasculares.', 'Tabletas 10 mg, 20 mg, 40 mg, 80 mg', 'Inicial: 10-20 mg una vez al dia (noche). Rango: 10-80 mg/dia.', 'Pfizer / Lipitor', 'Hipolipemiante', 'Mialgia, miopatia, elevacion de transaminasas, raramente rabdomiolisis. Cefalea, trastornos gastrointestinales.', 'Hepatopatia activa, embarazo y lactancia, hipersensibilidad. Precaucion con interacciones medicamentosas.'),
('Losartan', 'Antagonista del receptor de angiotensina II (ARA-II). Antihipertensivo que no causa tos. Proteccion cardiovascular y renal.', 'Tabletas 25 mg, 50 mg, 100 mg', 'Inicial: 50 mg una vez al dia. Rango: 25-100 mg/dia.', 'Merck / Cozaar', 'Antihipertensivo/ARA-II', 'Hiperpotasemia, hipotension, mareo, deterioro de funcion renal. Menos tos que IECAs.', 'Embarazo (teratogeno), hiperpotasemia severa.'),
('Omeprazol', 'Inhibidor de la bomba de protones (IBP). Bloquea la secrecion acida gastrica. Tratamiento de ulceras, ERGE y gastroproteccion en usuarios de AINEs.', 'Capsulas 20 mg, 40 mg; Vial IV 40 mg', 'ERGE: 20 mg/dia. Ulcera peptica: 20-40 mg/dia. Erradicacion H. pylori: 20 mg 2 veces/dia.', 'AstraZeneca / Prilosec', 'Antiulceroso/IBP', 'Cefalea, diarrea, estrenimieno, nauseas. Uso prolongado: hipomagnesemia, hipocalcemia, fractura osea.', 'Hipersensibilidad a IBPs, uso con nelfinavir. Precaucion en hepatopatia severa.'),
('Amlodipino', 'Bloqueante de los canales de calcio dihidropiridinico. Antihipertensivo y antianginoso de accion prolongada. Bien tolerado en la mayoria de pacientes.', 'Tabletas 5 mg, 10 mg', 'Hipertension/angina: inicial 5 mg/dia. Maximo 10 mg/dia. Toma unica diaria.', 'Pfizer / Norvasc', 'Antihipertensivo/BCC', 'Edema periferico (tobillo), rubefaccion, palpitaciones, cefalea, mareo. Raramente: hiperplasia gingival.', 'Hipersensibilidad a dihidropiridinas, shock cardiogenico, angina inestable severa.'),
('Metoprolol', 'Betabloqueante cardioselectivo B1. Reduce la frecuencia cardiaca y la presion arterial. Indicado en hipertension, angina, post-infarto e insuficiencia cardiaca.', 'Tabletas 50 mg, 100 mg (liberacion inmediata y prolongada)', 'Hipertension: 50-200 mg/dia en 1-2 dosis. IC: inicio 12.5-25 mg/dia, incremento gradual.', 'AstraZeneca / Lopressor', 'Betabloqueante', 'Bradicardia, fatiga, frio en extremidades, broncoespasmo leve, disfuncion erectil, depresion.', 'Asma grave o EPOC, bradicardia sinusal, bloqueo AV 2-3 grado, shock cardiogenico.'),
('Azitromicina', 'Antibiotico macrolido de amplio espectro. Inhibe la sintesis proteica bacteriana. Tratamiento de infecciones respiratorias, ITS y de piel.', 'Capsulas 250 mg, 500 mg; Suspension 200 mg/5 mL', 'Adultos: 500 mg dia 1, luego 250 mg dias 2-5. ITS: 1 g dosis unica.', 'Pfizer / Zithromax', 'Antibiótico', 'Nauseas, diarrea, dolor abdominal. Raramente: prolongacion QT, hepatotoxicidad, reacciones alergicas.', 'Hipersensibilidad a macrolidos, hepatopatia severa, arritmias cardiacas.'),
('Loratadina', 'Antihistaminico de segunda generacion. Antagonista selectivo del receptor H1 periferico. No cruza la barrera hematoencefalica significativamente (no sedante).', 'Tabletas 10 mg; Jarabe 5 mg/5 mL', 'Adultos y ninos >12 anos: 10 mg una vez al dia. Ninos 2-12 anos: 5 mg/dia.', 'Schering-Plough / Claritin', 'Antihistamínico', 'Cefalea, somnolencia leve, sequedad de boca, taquicardia (rara).', 'Hipersensibilidad a loratadina. Precaucion en insuficiencia hepatica severa.'),
('Diazepam', 'Benzodiacepina de accion prolongada. Ansiliolitico, sedante, anticonvulsivante y relajante muscular. Potencia la accion del GABA en el SNC.', 'Tabletas 2 mg, 5 mg, 10 mg; Solucion IV 5 mg/mL', 'Ansiedad: 2-10 mg 2-4 veces/dia. Convulsiones: 5-10 mg IV/IM. Maximo 30 mg/episodio.', 'Roche / Valium', 'Ansiolítico', 'Sedacion, somnolencia, ataxia, confusion, dependencia fisica y psicologica, depresion respiratoria en sobredosis.', 'Miastenia gravis, insuficiencia respiratoria severa, apnea del sueno, embarazo 1er trimestre.'),
('Insulina Glargina', 'Insulina analoga de accion prolongada (24 horas). Sin pico pronunciado. Control glucemico basal en diabetes tipo 1 y 2. Administracion subcutanea.', 'Solucion inyectable 100 UI/mL (pluma precargada)', 'Individualizar dosis. Inicial en DM2: 10 UI/dia SC a la misma hora. Ajustar segun glucemia basal.', 'Sanofi / Lantus', 'Insulina', 'Hipoglucemia (principal riesgo), reacciones en sitio de inyeccion, lipodistrofia, aumento de peso.', 'Hipoglucemia activa. No mezclar con otras insulinas. Ajuste en insuficiencia renal o hepatica.'),
('Prednisona', 'Corticosteroide oral de accion intermedia. Potente antiinflamatorio e inmunosupresor. Usado en enfermedades autoinmunes, alergicas e inflamatorias.', 'Tabletas 5 mg, 20 mg, 50 mg', 'Dosis variable: 5-60 mg/dia segun indicacion. Reducir gradualmente al suspender.', 'Pfizer / Deltasone', 'Corticosteroide', 'Hiperglucemia, hipertension, osteoporosis, aumento de peso, sindrome de Cushing, ulcera peptica.', 'Infecciones sistemicas no controladas, tuberculosis activa, herpes simplex ocular.'),
('Ciprofloxacino', 'Antibiotico fluoroquinolona de amplio espectro. Inhibe la ADN girasa bacteriana. Eficaz en infecciones urinarias, gastrointestinales y respiratorias.', 'Tabletas 250 mg, 500 mg, 750 mg; Solucion IV 2 mg/mL', 'ITU no complicada: 250-500 mg cada 12 horas por 3-7 dias. Otras: 500-750 mg cada 12 horas.', 'Bayer / Cipro', 'Antibiótico', 'Nauseas, diarrea, cefalea. Raramente: tendinitis, prolongacion QT, convulsiones, fotosensibilidad.', 'Menores de 18 anos (excepto especial), embarazo, epilepsia no controlada. No tomar con antiacidos.'),
('Warfarina', 'Anticoagulante oral antagonista de la vitamina K. Previene trombos. Requiere monitorizacion del INR. Numerosas interacciones con alimentos y medicamentos.', 'Tabletas 1 mg, 2 mg, 2.5 mg, 5 mg', 'Dosis ajustada segun INR (objetivo 2-3). Toma unica diaria a la misma hora. Inicio 2-5 mg/dia.', 'Bristol-Myers / Coumadin', 'Anticoagulante', 'Hemorragia (principal riesgo), necrosis cutanea, alopecia. Requiere monitorizacion periodica del INR.', 'Embarazo, hemorragia activa, HTA severa no controlada, cirugia reciente del SNC.'),
('Salbutamol', 'Agonista B2-adrenergico de accion corta (SABA). Broncodilatador de rescate en asma y EPOC. Relaja el musculo liso bronquial en minutos.', 'Inhalador 100 mcg/dosis; Nebulizacion 5 mg/mL; Tabletas 2 mg, 4 mg', 'Crisis aguda: 2-4 pulsaciones cada 20 min por 3 dosis. Mantenimiento: 2 pulsaciones cada 4-6 horas.', 'GlaxoSmithKline / Ventolin', 'Broncodilatador', 'Temblor fino, taquicardia, cefalea, palpitaciones, hipopotasemia (dosis altas), nerviosismo.', 'Hipersensibilidad a salbutamol. Precaucion en cardiopatia isquemica, hipertiroidismo.'),
('Levotiroxina', 'Hormona tiroidea sintetica (T4). Tratamiento del hipotiroidismo y bocio. Reemplaza la hormona tiroidea endogena. Administracion matinal en ayunas.', 'Tabletas 25 mcg, 50 mcg, 75 mcg, 100 mcg, 150 mcg', 'Individualizar. Inicio: 25-50 mcg/dia. Incremento gradual cada 4-6 semanas. Controlar TSH.', 'Abbott / Synthroid', 'Hormona Tiroidea', 'Sintomas de hipertiroidismo si sobredosificacion: taquicardia, insomnio, perdida de peso, temblor.', 'Tirotoxicosis no tratada, infarto reciente, insuficiencia suprarrenal no tratada.'),
('Clopidogrel', 'Antiagregante plaquetario inhibidor del receptor P2Y12 del ADP. Previene trombosis arterial. Usado en sindrome coronario agudo, angioplastia e ictus isquemico.', 'Tabletas 75 mg, 300 mg', 'Profilaxis: 75 mg una vez al dia. Dosis de carga SCA/stent: 300-600 mg. Combinado con aspirina.', 'Sanofi / Plavix', 'Antiagregante', 'Sangrado (principal riesgo), equimosis, hematomas, dispepsia, diarrea, raramente PTT.', 'Hemorragia activa, hipersensibilidad. Precaucion en riesgo hemorragico. Interaccion con omeprazol.');
